 题目 # 难度：Medium
给你一个大小为 m x n 的矩阵 mat ，请以对角线遍历的顺序，用一个数组返回这个矩阵中的所有元素。
&nbsp;
示例 1：
输入：mat = [[1,2,3],[4,5,6],[7,8,9]] 输出：[1,2,4,7,5,3,6,8,9] 示例 2：
输入：mat = [[1,2],[3,4]] 输出：[1,2,3,4] &nbsp;
提示：
m == mat.length n == mat[i].length 1 &lt;= m, n &lt;= 104 1 &lt;= m * n &lt;= 104 -105 &lt;= mat[i][j] &lt;= 105 分析 # 直接法，第一条线是在00上，第二条线是01 10，第三条线是02 11 20。每条线的i，j之和是相同的。所以可以通过设置两个和为定值的变量进行控制每条线上数组的内容，此外还要注意方向，每转一次都要改变方向，这个可以使用s的奇偶来判断。
题解 # class Solution { public: vector&lt;int&gt; findDiagonalOrder(vector&lt;vector&lt;int&gt;&gt;&amp; mat) { int m = mat.size(); int n = mat[0].size(); vector&lt;int&gt; ans; for(int s = 0;s &lt; m + n - 1 ;s++){ for(int i = 0 ; s-i&gt;=0 ;i++){ if(s%2 == 1){ if(s - i &lt; n &amp;&amp; i &lt; m ) ans.push_back(mat[i][s-i]); } else{ if(s - i &lt; m &amp;&amp; i &lt; n) ans.push_back(mat[s-i][i]); } } } return ans; } }; //优化版 class Solution { public: vector&lt;int&gt; findDiagonalOrder(vector&lt;vector&lt;int&gt;&gt;&amp; mat){ int m = mat.size(); int n = mat[0].size(); vector&lt;int&gt; ans; for(int s = 0;s &lt; m + n - 1 ;s++){ if(!(s%2)){ int row =(s &lt; m)?s:m-1; int col =s - row; while(col &lt; n &amp;&amp; row &gt;= 0){ ans.push_back(mat[row--][col++]); } }else{ int col = (s &lt; n)?s:n - 1; int row = s - col; while(col &gt;= 0 &amp;&amp; row &lt; m){ ans.push_back(mat[row++][col--]); } } } return ans; } };

