n == difficulty.length n == profit.length m == worker.length 1 &lt;= n, m &lt;= 104 1 &lt;= difficulty[i], profit[i], worker[i] &lt;= 105 分析 # 题解 # class Solution { public: int maxProfitAssignment(vector&lt;int&gt;&amp; difficulty, vector&lt;int&gt;&amp; profit, vector&lt;int&gt;&amp; worker) { } };

