示例 1：
输入：head = [2,1,5] 输出：[5,5,0] 示例 2：
输入：head = [2,7,4,3,5] 输出：[7,0,5,5,0] &nbsp;
提示：
链表中节点数为&nbsp;n 1 &lt;= n &lt;= 104 1 &lt;= Node.val &lt;= 109 分析 # 题解 # /** * Definition for singly-linked list. * struct ListNode { * int val; * ListNode *next; * ListNode() : val(0), next(nullptr) {} * ListNode(int x) : val(x), next(nullptr) {} * ListNode(int x, ListNode *next) : val(x), next(next) {} * }; */ class Solution { public: vector&lt;int&gt; nextLargerNodes(ListNode* head) { } };

