提示：
1 &lt;= nums1.length, nums2.length &lt;= 1000 -1000 &lt;= nums1[i], nums2[i] &lt;= 1000 分析 # 题解 # class Solution { public: vector&lt;vector&lt;int&gt;&gt; findDifference(vector&lt;int&gt;&amp; nums1, vector&lt;int&gt;&amp; nums2) { } };

