 题目 # 难度：Easy
请实现一个函数，把字符串 s 中的每个空格替换成&quot;%20&quot;。
&nbsp;
示例 1：
输入：s = &quot;We are happy.&quot; 输出：&quot;We%20are%20happy.&quot; &nbsp;
限制：
0 &lt;= s 的长度 &lt;= 10000
分析 # 题意是查找空格并替换，可以遍历这个字符串然后找到空格，然后替换。可以采用原地替换，不过要扩充长度。 也可以定义一个新字符串，长度为三倍的输入字符串长度，因为最坏情况为全是空格，也可以遍历字符串查询有多少个空格然后再根据数量判断字符串长度。
题解 # class Solution { public: string replaceSpace(string s) { string ans; for(int i = 0;i&lt;s.length();i++){ if(s[i] == 32) { ans.push_back(&#39;%&#39;); ans.push_back(&#39;2&#39;); ans.push_back(&#39;0&#39;); } else { ans.push_back(s[i]); } } return ans; } }; // 原地修改 class Solution { public: string replaceSpace(string s) { int count = 0, len = s.size(); // 统计空格数量 for (char c : s) { if (c == &#39; &#39;) count++; } // 修改 s 长度 s.resize(len + 2 * count); // 倒序遍历修改 for(int i = len - 1, j = s.size() - 1; i &lt; j; i--, j--) { if (s[i] != &#39; &#39;) s[j] = s[i]; else { s[j - 2] = &#39;%&#39;; s[j - 1] = &#39;2&#39;; s[j] = &#39;0&#39;; j -= 2; } } return s; } };

