 数据结构 # vector[可变数组] # vector是一种变长数组，即可以自动改变长度的数组。 头文件
#include&lt;vector&gt; 初始化
#include&lt;iostream&gt; #include&lt;vector&gt; using namespace std; int main () { //几种初始化的方法 vector&lt;int&gt; a;//定义一个vector 未初始化 输出》 0 vector&lt;int&gt; a(3);//定义一个长度为3的vector 未初始化 输出》0 0 0 vector&lt;int&gt; a(10, 3); //定义一个长度为10，且每个数赋值为3 //将向量b中从下标0 1 2（共三个）的元素赋值给a，a的类型为int型 //它的初始化不和数组一样 vector&lt;int&gt;a(b.begin(),b.begin+3); //从数组中获得初值 int b[7]={1,2,3,4,5,6,7}; vector&lt;int&gt; a(b,b+7）; for(auto x : a) {//遍历输出 cout &lt;&lt; x &lt;&lt; &#34; &#34;; } return 0; } 相关函数
a.size();//返回元素个数 a.resize();//改变大小 a.empty();//判断a是否为空，空则返回true，非空则返回false a.front(); //返回a的第1个元素,当且仅当a存在 a.back(); //返回vector的最后一个数 a.clear(); //清空a中的元素 a.pop_back(); //删除a向量的最后一个元素 a.push_back(5); //在a的最后一个向量后插入一个元素，其值为5 a.begin();// vector的第0个数 a.end();// vector的最后一个的数的后面一个数 //通常与for循环结合使用 ⑦倍增的思想
